#!/bin/bash&#10;# Unified Production Deploy Script for OSCAR BROOME REVENUE&#10;&#10;set -e&#10;&#10;echo "🚀 OSCAR BROOME REVENUE - PRODUCTION DEPLOYMENT"&#10;echo "=================================================="&#10;&#10;# Colors&#10;RED=&#39;\\e[31m&#39;&#10;GREEN=&#39;\\e[32m&#39;&#10;YELLOW=&#39;\\e[33m&#39;&#10;BLUE=&#39;\\e[34m&#39;&#10;NC=&#39;\\e[0m&#39; # No Color&#10;&#10;DEPLOY_MODE=${1:-local}&#10;&#10;log_info() { echo -e "${BLUE}[INFO]${NC} $1"; }&#10;log_success() { echo -e "${GREEN}[SUCCESS]${NC} $1"; }&#10;log_warn() { echo -e "${YELLOW}[WARN]${NC} $1"; }&#10;log_error() { echo -e "${RED}[ERROR]${NC} $1"; exit 1; }&#10;&#10;check_prereq() {&#10;  command -v docker &amp;>/dev/null &amp;&amp; command -v docker-compose &amp;>/dev/null &amp;&amp;&#10;  command -v node &amp;>/dev/null &amp;&amp; command -v npm &amp;>/dev/null &amp;&amp;&#10;  command -v pm2 &amp;>/dev/null ||&#10;    log_error "Missing prerequisites: docker, docker-compose, node, npm, pm2"&#10;}&#10;&#10;install_prereqs() {&#10;  log_info "Installing PM2 globally..."&#10;  npm install -g pm2&#10;}&#10;&#10;setup_env() {&#10;  if [ ! -f .env.production ]; then&#10;    cp production/.env.production.example .env.production&#10;    log_warn ".env.production created from template. EDIT YOUR SECRETS!"&#10;  fi&#10;}&#10;&#10;npm_install() {&#10;  log_info "Installing dependencies..."&#10;  npm ci --production&#10;}&#10;&#10;pm2_deploy() {&#10;  log_info "PM2 deployment (non-Docker)..."&#10;  pm2 delete all || true&#10;  pm2 start ecosystem.config.js --env production&#10;  pm2 save&#10;  pm2 logs oscar-broome-revenue&#10;}&#10;&#10;docker_deploy() {&#10;  log_info "Docker Compose deployment..."&#10;  docker-compose -f docker-compose.production.yml down || true&#10;  docker-compose -f docker-compose.production.yml build&#10;  docker-compose -f docker-compose.production.yml up -d&#10;  docker-compose -f docker-compose.production.yml logs -f app&#10;}&#10;&#10;case $DEPLOY_MODE in&#10;  "local-pm2")&#10;    check_prereq&#10;    setup_env&#10;    npm_install&#10;    pm2_deploy&#10;    ;;&#10;  "local-docker")&#10;    check_prereq&#10;    setup_env&#10;    docker_deploy&#10;    ;;&#10;  "aws")&#10;    log_info "AWS deployment (manual ECS/EC2 setup needed)"&#10;    # Add AWS specific logic&#10;    exit 0&#10;    ;;&#10;  *)&#10;    log_error "Usage: bash production/deploy-prod.sh [local-pm2|local-docker|aws]"&#10;    ;;&#10;esac&#10;&#10;log_success "🚀 Production ready! Check http://localhost:3000/health"
